import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { getSupabaseClient } from '@/integrations/supabase/client';
import { realtimeEventProcessor } from '@/shared/realtime/RealtimeEventProcessor';
import type { AssetRegistryEntry, ResolvedAssetRegistryEntry } from '@/tools/video-editor/types';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData.types';

interface PrimaryVariantInfo {
  location: string;
  variant_id: string;
}

interface UseStaleVariantsArgs {
  registry: Record<string, ResolvedAssetRegistryEntry> | undefined;
  patchRegistry: UseTimelineDataResult['patchRegistry'];
  registerAsset: UseTimelineDataResult['registerAsset'];
}

const POLL_INTERVAL_MS = 15_000;

/**
 * Checks which asset registry entries reference a variant that is no longer
 * the primary variant of its generation. Uses direct Supabase queries + realtime
 * subscription (no React Query) for predictable, immediate updates.
 */
export function useStaleVariants({ registry, patchRegistry, registerAsset }: UseStaleVariantsArgs) {
  const [primaryLocationMap, setPrimaryLocationMap] = useState<Record<string, PrimaryVariantInfo | null>>({});
  const [dismissedAssetKeys, setDismissedAssetKeys] = useState<Set<string>>(() => new Set());
  const fetchCounterRef = useRef(0);

  // Collect all asset keys linked to a generation
  const generationAssetMap = useMemo(() => {
    if (!registry) {
      return {
        generationIds: [] as string[],
        assetsByGeneration: {} as Record<string, { assetKey: string; file: string }[]>,
        generationAssetKeys: new Set<string>(),
      };
    }

    const assetsByGeneration: Record<string, { assetKey: string; file: string }[]> = {};
    const generationAssetKeys = new Set<string>();

    for (const [assetKey, entry] of Object.entries(registry)) {
      if (entry.generationId) {
        generationAssetKeys.add(assetKey);
        if (!assetsByGeneration[entry.generationId]) {
          assetsByGeneration[entry.generationId] = [];
        }
        assetsByGeneration[entry.generationId].push({ assetKey, file: entry.file });
      }
    }

    return {
      generationIds: Object.keys(assetsByGeneration),
      assetsByGeneration,
      generationAssetKeys,
    };
  }, [registry]);

  // Fetch primary variant locations from Supabase
  const fetchPrimaryLocations = useCallback(async (generationIds: string[]) => {
    if (generationIds.length === 0) {
      setPrimaryLocationMap({});
      return;
    }

    const fetchId = ++fetchCounterRef.current;

    const { data, error } = await getSupabaseClient()
      .from('generations')
      .select(`
        id,
        primary_variant:generation_variants!generations_primary_variant_id_fkey (
          id,
          location
        )
      `)
      .in('id', generationIds);

    if (error) {
      console.error('[StaleVariants] fetch error:', error);
      return;
    }

    // Discard if a newer fetch has started
    if (fetchId !== fetchCounterRef.current) return;

    const map: Record<string, PrimaryVariantInfo | null> = {};
    for (const row of data ?? []) {
      const pv = row.primary_variant as { id: string; location: string } | null;
      map[row.id] = pv ? { location: pv.location, variant_id: pv.id } : null;
    }

    setPrimaryLocationMap(map);
  }, []);

  // Fetch on mount, when generationIds change, and on a polling interval
  useEffect(() => {
    const { generationIds } = generationAssetMap;
    if (generationIds.length === 0) return;

    // Immediate fetch
    void fetchPrimaryLocations(generationIds);

    // Poll every 15 seconds as fallback
    const interval = setInterval(() => {
      void fetchPrimaryLocations(generationIds);
    }, POLL_INTERVAL_MS);

    return () => clearInterval(interval);
  }, [generationAssetMap, fetchPrimaryLocations]);

  // Subscribe to realtime variant/generation changes for instant updates
  useEffect(() => {
    const { generationIds } = generationAssetMap;
    if (generationIds.length === 0) return;

    const genIdSet = new Set(generationIds);

    return realtimeEventProcessor.onEvent((event) => {
      // Variant inserted/updated (e.g., new primary variant set)
      if (event.type === 'variants-changed') {
        const relevant = event.affectedGenerationIds.some((id) => genIdSet.has(id));
        if (relevant) {
          void fetchPrimaryLocations(generationIds);
        }
        return;
      }

      // Generation updated (e.g., primary_variant_id changed)
      if (event.type === 'generations-updated') {
        const relevant = event.generations.some((g) => genIdSet.has(g.id));
        if (relevant) {
          void fetchPrimaryLocations(generationIds);
        }
      }
    });
  }, [generationAssetMap, fetchPrimaryLocations]);

  // Build the set of stale asset keys (compare by file URL)
  const staleAssetKeys = useMemo(() => {
    const stale = new Set<string>();

    for (const [generationId, assets] of Object.entries(generationAssetMap.assetsByGeneration)) {
      const primaryInfo = primaryLocationMap[generationId];
      if (!primaryInfo) continue;
      for (const { assetKey, file } of assets) {
        if (file !== primaryInfo.location) {
          stale.add(assetKey);
        }
      }
    }

    return stale;
  }, [primaryLocationMap, generationAssetMap.assetsByGeneration]);

  const dismissAsset = useCallback((assetKey: string) => {
    setDismissedAssetKeys((prev) => {
      const next = new Set(prev);
      next.add(assetKey);
      return next;
    });
  }, []);

  // Update a single asset to the current primary variant
  const updateAssetToCurrentVariant = useCallback(async (assetKey: string) => {
    if (!registry) return;
    const entry = registry[assetKey];
    if (!entry?.generationId) return;

    // Fetch the current primary variant's data
    const { data, error } = await getSupabaseClient()
      .from('generations')
      .select(`
        primary_variant_id,
        primary_variant:generation_variants!generations_primary_variant_id_fkey (
          id,
          location,
          thumbnail_url
        )
      `)
      .eq('id', entry.generationId)
      .single();

    if (error || !data?.primary_variant) return;

    const newVariant = data.primary_variant as { id: string; location: string; thumbnail_url: string | null };
    const newLocation = newVariant.location;

    const updatedEntry: AssetRegistryEntry = {
      ...entry,
      file: newLocation,
      variantId: newVariant.id,
    };

    // Update in-memory registry
    patchRegistry(assetKey, updatedEntry, newLocation);

    // Persist to DB
    void registerAsset(assetKey, updatedEntry).catch((err) => {
      console.error('[StaleVariants] Failed to persist variant update:', err);
    });

    // Clear dismiss state (it's now up to date)
    setDismissedAssetKeys((prev) => {
      if (!prev.has(assetKey)) return prev;
      const next = new Set(prev);
      next.delete(assetKey);
      return next;
    });
  }, [registry, patchRegistry, registerAsset]);

  return {
    staleAssetKeys,
    dismissedAssetKeys,
    generationAssetKeys: generationAssetMap.generationAssetKeys,
    dismissAsset,
    updateAssetToCurrentVariant,
  };
}

import { useMemo } from 'react';
import { useTimelineEditorContext } from '@/tools/video-editor/contexts/TimelineEditorContext';

export type SelectedMediaClip = {
  clipId: string;
  assetKey: string;
  url: string;
  mediaType: 'image' | 'video';
  generationId?: string;
};

function formatAttachmentCount(count: number, mediaType: 'image' | 'video') {
  if (count === 1) {
    return `1 ${mediaType}`;
  }

  return `${count} ${mediaType}s`;
}

export function buildSummary(imageCount: number, videoCount: number) {
  const parts = [
    imageCount > 0 ? formatAttachmentCount(imageCount, 'image') : null,
    videoCount > 0 ? formatAttachmentCount(videoCount, 'video') : null,
  ].filter((part): part is string => part !== null);

  return parts.length > 0 ? `attaching ${parts.join(', ')}` : '';
}

export function useSelectedMediaClips(): { clips: SelectedMediaClip[]; summary: string } {
  const { selectedClipIds, resolvedConfig } = useTimelineEditorContext();

  return useMemo(() => {
    if (!resolvedConfig || selectedClipIds.size === 0) {
      return { clips: [], summary: '' };
    }

    const clips = [...selectedClipIds].flatMap((clipId) => {
      const clip = resolvedConfig.clips.find((item) => item.id === clipId);
      const assetKey = clip?.asset;
      const assetEntry = assetKey ? resolvedConfig.registry[assetKey] : undefined;

      if (!assetKey || !assetEntry?.src || !assetEntry.type) {
        return [];
      }

      if (assetEntry.type.startsWith('image/')) {
        return [{
          clipId,
          assetKey,
          url: assetEntry.src,
          mediaType: 'image' as const,
          generationId: assetEntry.generationId,
        }];
      }

      if (assetEntry.type.startsWith('video/')) {
        return [{
          clipId,
          assetKey,
          url: assetEntry.src,
          mediaType: 'video' as const,
          generationId: assetEntry.generationId,
        }];
      }

      return [];
    });

    const imageCount = clips.filter((clip) => clip.mediaType === 'image').length;
    const videoCount = clips.length - imageCount;

    return {
      clips,
      summary: buildSummary(imageCount, videoCount),
    };
  }, [resolvedConfig, selectedClipIds]);
}

import { useMemo } from 'react';
import type { Shot } from '@/domains/generation/types';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type { AssetRegistry } from '@/tools/video-editor/types';
import type { TimelineAction, TimelineRow } from '@/tools/video-editor/types/timeline-canvas';

const MAX_GAP_SECONDS = 0.5;
const SHOT_COLORS = ['#a855f7', '#ef4444', '#22c55e', '#3b82f6', '#f59e0b', '#14b8a6', '#ec4899', '#84cc16'];

export interface ShotGroup {
  shotId: string;
  shotName: string;
  rowId: string;
  rowIndex: number;
  clipIds: string[];
  color: string;
}

export function getShotColor(shotId: string): string {
  let hash = 0;

  for (let index = 0; index < shotId.length; index += 1) {
    hash = ((hash * 31) + shotId.charCodeAt(index)) >>> 0;
  }

  return SHOT_COLORS[hash % SHOT_COLORS.length];
}

function flushGroup(groups: ShotGroup[], group: ShotGroup | null) {
  if (group && group.clipIds.length >= 2) {
    groups.push(group);
  }
}

function sortActions(actions: TimelineAction[]) {
  return [...actions].sort((left, right) => left.start - right.start || left.end - right.end || left.id.localeCompare(right.id));
}

export function useShotGroups(
  rows: TimelineRow[],
  meta: Record<string, ClipMeta>,
  registry: AssetRegistry,
  shots: Shot[] | undefined,
): ShotGroup[] {
  return useMemo(() => {
    if (!shots?.length || rows.length === 0) {
      return [];
    }

    const clipGenerationIds = new Map<string, string>();
    for (const row of rows) {
      for (const action of row.actions) {
        const assetKey = meta[action.id]?.asset;
        const generationId = assetKey ? registry.assets[assetKey]?.generationId : undefined;
        if (typeof generationId === 'string' && generationId.length > 0) {
          clipGenerationIds.set(action.id, generationId);
        }
      }
    }

    const groups: ShotGroup[] = [];

    for (const shot of shots) {
      const imageIndexByGenerationId = new Map<string, number>();
      for (const [imageIndex, image] of (shot.images ?? []).entries()) {
        const generationId = image.generation_id;
        if (typeof generationId === 'string' && generationId.length > 0 && !imageIndexByGenerationId.has(generationId)) {
          imageIndexByGenerationId.set(generationId, imageIndex);
        }
      }

      if (imageIndexByGenerationId.size < 2) {
        continue;
      }

      const color = getShotColor(shot.id);

      for (const [rowIndex, row] of rows.entries()) {
        let currentGroup: ShotGroup | null = null;
        let lastImageIndex = -1;
        let lastEnd = 0;

        for (const action of sortActions(row.actions)) {
          const generationId = clipGenerationIds.get(action.id);
          const imageIndex = generationId ? imageIndexByGenerationId.get(generationId) : undefined;

          if (imageIndex === undefined) {
            flushGroup(groups, currentGroup);
            currentGroup = null;
            lastImageIndex = -1;
            lastEnd = 0;
            continue;
          }

          if (!currentGroup) {
            currentGroup = {
              shotId: shot.id,
              shotName: shot.name,
              rowId: row.id,
              rowIndex,
              clipIds: [action.id],
              color,
            };
            lastImageIndex = imageIndex;
            lastEnd = action.end;
            continue;
          }

          if (action.start - lastEnd < MAX_GAP_SECONDS && imageIndex > lastImageIndex) {
            currentGroup.clipIds.push(action.id);
            lastImageIndex = imageIndex;
            lastEnd = action.end;
            continue;
          }

          flushGroup(groups, currentGroup);
          currentGroup = {
            shotId: shot.id,
            shotName: shot.name,
            rowId: row.id,
            rowIndex,
            clipIds: [action.id],
            color,
          };
          lastImageIndex = imageIndex;
          lastEnd = action.end;
        }

        flushGroup(groups, currentGroup);
      }
    }

    return groups;
  }, [rows, meta, registry, shots]);
}

